<template>
    <section>
        <loader :is-visible="isLoading"></loader>
        <tg-list :IsShowAction="true" :showCheckBox="true" ModuleName="BillingRule" :listType="['List']"
            :RenderRowActionMethod="renderActions" v-on:ActionButtonClick="actionButtonClick" SubModuleCode=""
            IdentityColumn="CONFIGURATION_ID" :HeaderText="$t('ManageBillingRule')" :ListData="BillingRuleData"
            :HeaderData="Headers" :callbackfunction="FetchData" :HeaderButtons="listheaderbuttons"
            :TotalRecords="TotalRecords" :SearchFields="leftSearchFields" :ListDataCallBackFunction="FetchData"
            :LegendArray="[]" :SortExp="sortExp" :SortBy="SortBy" :NorecordfoundText="$t('NoRecordfound')"
            v-on:LeftsearchButtonClick="leftCommonSearch" v-on:PagerButtonClick="pagerMethod"
            v-on:HeaderButtonClick="commonHeaderButtonClick" v-on:SortdataButtonClick="sortdata">
            <template v-slot:slotdata="{ data }">
                <!-- {{ data.row }} -->
                <template v-if="data.column.COLUMN_NAME == 'RULE_NAME'">
                    <a href="javascript:;" v-on:click="OpenRuleDetail(data.row)"><i
                            aria-hidden="true"></i>{{
                                data.row.RULE_NAME }}
                    </a>
                </template>
                <template v-if="data.column.COLUMN_NAME == 'CATEGORY_NAME'">
                    <span v-if="data.row.CATEGORY_NAME != null || data.row.CATEGORY_NAME != ''">
                        {{ data.row.CATEGORY_NAME }}
                    </span>
                    <span v-else>--</span>
                </template>
                <template v-if="data.column.COLUMN_NAME == 'CLIENT_NAME'">
                    <span v-if="data.row.CLIENT_NAME != null || data.row.CLIENT_NAME != ''">
                        {{ data.row.CLIENT_NAME }}
                    </span>
                    <span v-else>--</span>
                </template>
                <template v-if="data.column.COLUMN_NAME == 'UTILITYNAME'">
                    <span v-if="data.row.UTILITYNAME != null || data.row.UTILITYNAME != ''">
                        {{ data.row.UTILITYNAME }}
                    </span>
                    <span v-else>--</span>
                </template>
                <template v-if="data.column.COLUMN_NAME == 'STATENAME'">
                    <span v-if="data.row.STATENAME != null || data.row.STATENAME != ''">
                        {{ data.row.STATENAME }}
                    </span>
                    <span v-else>--</span>
                </template>
                <template v-if="data.column.COLUMN_NAME == 'EFFICATIVE_DATE_FROM'">
                    <td class="text-center single-action tourguide_a" v-if="data.row.EFFICATIVE_DATE_FROM">
                        {{ $d(data.row.EFFICATIVE_DATE_FROM) }}
                    </td>
                    <td class="text-center single-action tourguide_a" v-else>--</td>
                </template>
                <template v-if="data.column.COLUMN_NAME == 'EFFICATIVE_DATE_TO'">
                    <td class="text-center single-action tourguide_a" v-if="data.row.EFFICATIVE_DATE_TO">
                        {{ $d(data.row.EFFICATIVE_DATE_TO) }}
                    </td>
                    <td class="text-center single-action tourguide_a" v-else>--</td>

                </template>
                <template v-if="data.column.COLUMN_NAME == 'CREATED_AT'">
                    <td class="text-center single-action tourguide_a" v-if="data.row.CREATED_AT">
                        {{ $d(data.row.CREATED_AT) }}
                    </td>
                    <td class="text-center single-action tourguide_a" v-else>--</td>

                </template>
                <template v-if="data.column.COLUMN_NAME == 'MODIFIED_AT'">
                    <td class="text-center single-action tourguide_a" v-if="data.row.MODIFIED_AT">
                        {{ $d(data.row.MODIFIED_AT) }}
                    </td>
                    <td class="text-center single-action tourguide_a" v-else>--</td>

                </template>
                <template v-if="data.column.COLUMN_NAME == 'MODIFIED_BY_NAME'">
                    <td class="text-center single-action tourguide_a"
                        v-if="data.row.MODIFIED_BY_NAME">
                        {{ data.row.MODIFIED_BY_NAME }}
                    </td>
                    <td class="text-center single-action tourguide_a" v-else>--</td>
                </template>
                <template v-if="data.column.COLUMN_NAME == 'STATUS_ID'">
                    <div>
                        <listing-status :isfor="'Billing_Rule'" ref="updatestatus"
                            v-bind:dataid="data.row.CONFIGURATION_ID" data-controller="Billing_Rule"
                            v-bind:statuslist="StatusListForListing" v-bind:item="data.row.STATUS_ID"
                            data-action="index" v-bind:dataselected="data.row.STATUS_ID == 1001 ? 'Active' : 'Inactive'"
                            v-bind:callbackfunction="FetchData" v-bind:isselectedvaluestring="true" v-bind:title="data.row.STATUS_ID == 1001 ? 'Active' : 'Inactive'">
                        </listing-status>
                    </div>
                    <div>
                        <span v-bind:class="getStatusClassList(data.row.STATUS_ID, 'STATUS_ID')"
                            v-if="data.row.STATUS_ID == 'Active'">
                            {{ data.row.STATUS_ID }}
                        </span>
                        <span v-bind:class="getStatusClassList(data.row.STATUS_ID, 'STATUS_ID')"
                            v-if="data.row.STATUS_ID == 'Inactive'">
                            {{ data.row.STATUS_ID }}
                        </span>
                    </div>
                </template>
            </template>
        </tg-list>
        <!-- Clone Model  Start-->
        <div class="my-popups">
            <loader :is-visible="isLoading" />

            <div class="modal d-block" v-if="isCloneModel">
                <div class="modal-dialog modal-dialog-centered">
                    <div class="modal-content">
                        <div
                            class="modal-header theme-primary partition-full d-flex justify-content-between align-items-center">
                            <h5 class="modal-title">
                                {{ $t('CloneRule') }}
                            </h5>
                            <button type="button" class="close" @click="CloseCloneModel">
                                <em class="fa fa-times" aria-hidden="true"></em>
                            </button>
                        </div>

                        <div class="modal-body">
                            <dynamic-form lang="en" ref="validatePlan" :buttons="buttons" :schema="FormSchema"
                                :mandatorytext="$t('MandatoryString')">
                            </dynamic-form>
                        </div>
                    </div>
                </div>
            </div>
        </div>
        <!-- Clone Model End -->
        <BillingViewHistory v-if="isBillingHistoryPopup" :CONFIGURATION_ID="CONFIGURATION_ID" :BILLING_SERVICE_ID="BILLING_SERVICE_ID" :setupId="setupId" @close="isBillingHistoryPopup = false"></BillingViewHistory>
    </section>
</template>

<script>

import Schema from '../BillingRule/BillingRuleSchema';
import DataService from '../../services/DataService';
//import BillingViewHistory from '../../components/Modals/BillingViewHistory.vue';
import BillingViewHistory from '../../components/Modals/BillingViewHistory.vue';


import moment from 'moment';
import {
    locateBillingService
} from "../../services/locateBillingService";
export default {
     components: {BillingViewHistory},
    data() {
        return {
            isLoading: false,
            BillingRuleData: [],
            isCloneModel: false,
            listActions: Schema.listActions,
            listheaderbuttons: Schema.buttons,
            cloneItem: [],
            StatusListForListing: [
                {
                    STATUS: "Active",
                    STATUS_ID: 1001,
                    STATUS_COLOR: "#ffffff",
                    STATUS_BG_COLOR: "#28a745",
                },
                {
                    STATUS: "Inactive",
                    STATUS_ID: 1002,
                    STATUS_COLOR: "#ffffff",
                    STATUS_BG_COLOR: "#d72435",
                },
            ],
            Headers: [
                {
                    "COLUMN_NAME": "RULE_NAME",
                    "DATA_TYPE": "text",
                    "SORTABLE": true,
                    "VISIBLE": true,
                    "DISPLAY_NAME": this.$t('BillingRuleName'),
                    "DISPLAY_ORDER": 1,
                },
                {
                    "COLUMN_NAME": "SERVICE_NAME",
                    "DATA_TYPE": "text",
                    "SORTABLE": true,
                    "VISIBLE": false,
                    "DISPLAY_NAME":  this.$t('ServiceName'),
                    "DISPLAY_ORDER": 2,
                },
                {
                    "COLUMN_NAME": "CLIENT_NAME",
                    "DATA_TYPE": "text",
                    "SORTABLE": true,
                    "VISIBLE": false,
                    "DISPLAY_NAME": 'Contract',
                    "DISPLAY_ORDER": 2,
                },
                {
                    "COLUMN_NAME": "UTILITYNAME",
                    "DATA_TYPE": "text",
                    "SORTABLE": false,
                    "VISIBLE": false,
                    "DISPLAY_NAME": this.$t('UtilityName'),
                    "DISPLAY_ORDER": 3,
                },
                {
                    "COLUMN_NAME": "CATEGORY_NAME",
                    "DATA_TYPE": "text",
                    "SORTABLE": true,
                    "VISIBLE": false,
                    "DISPLAY_NAME": 'Category',
                    "DISPLAY_ORDER": 4,
                },
                {
                    "COLUMN_NAME": "STATENAME",
                    "DATA_TYPE": "text",
                    "SORTABLE": false,
                    "VISIBLE": false,
                    "DISPLAY_NAME": this.$t('State'),
                    "DISPLAY_ORDER": 5,
                },
                {
                    "COLUMN_NAME": "EFFICATIVE_DATE_FROM",
                    "DATA_TYPE": "text",
                    "SORTABLE": true,
                    "VISIBLE": true,
                    "DISPLAY_NAME": this.$t('EffectiveFromDate'),
                    "DISPLAY_ORDER": 6,
                },
                {
                    "COLUMN_NAME": "EFFICATIVE_DATE_TO",
                    "DATA_TYPE": "text",
                    "SORTABLE": true,
                    "VISIBLE": true,
                    "DISPLAY_NAME": this.$t('EffectiveToDate'),
                    "DISPLAY_ORDER": 7,
                },
                {
                    "COLUMN_NAME": "STATUS_ID",
                    "DATA_TYPE": "text",
                    "SORTABLE": false,
                    "VISIBLE": true,
                    "DISPLAY_NAME": this.$t('Status'),
                    "DISPLAY_ORDER": 8,
                },
                {
                    "COLUMN_NAME": "CREATED_BY_NAME",
                    "DATA_TYPE": "text",
                    "SORTABLE": false,
                    "VISIBLE": true,
                    "DISPLAY_NAME": this.$t('CreatedBy'),
                    "DISPLAY_ORDER": 9,
                },
                {
                    "COLUMN_NAME": "CREATED_AT",
                    "DATA_TYPE": "text",
                    "SORTABLE": false,
                    "VISIBLE": false,
                    "DISPLAY_NAME": this.$t('CreatedAt'),
                    "DISPLAY_ORDER": 9,
                },
                {
                    "COLUMN_NAME": "MODIFIED_BY_NAME",
                    "DATA_TYPE": "text",
                    "SORTABLE": false,
                    "VISIBLE": false,
                    "DISPLAY_NAME": this.$t('ModifiedBy'),
                    "DISPLAY_ORDER": 9,
                },
                {
                    "COLUMN_NAME": "MODIFIED_AT",
                    "DATA_TYPE": "text",
                    "SORTABLE": false,
                    "VISIBLE": false,
                    "DISPLAY_NAME": this.$t('ModifiedAt'),
                    "DISPLAY_ORDER": 9,
                }

            ],
            FormSchema: [
                {
                    layoutType: "double",
                    Data: [
                        {
                            astype: "TextField",
                            label: this.$t('RuleName'),
                            name: 'RuleName',
                            palceholder: this.$t('RuleName'),
                            value: "",
                            validationRules: {
                                required: true
                            },
                            disabled: false,
                        },
                        {
                            astype: "SelectField",
                            label: this.$t('CompanyId'),
                            name: "CompanyName",
                            value: "",
                            placeholder: this.$t('Select'),
                            config: {
                                options: []
                            },
                            validationRules: {
                                required: true
                            },
                        },
                        {
                            astype: "DateField",
                            label: this.$t('EffectiveFromDate')+' '+'(M/D/YYYY)',
                            name: "Effectivefrom",
                            value: new Date().toLocaleDateString(),
                            placeholder: "",
                            config: {
                                format: "MM/DD/YYYY",
                                minDate: new Date(),
                                onChange: this.setTimerDate,
                                maxDate: false
                            },
                            validationRules: { "required": true },
                        },
                        {
                            astype: "DateField",
                            label: this.$t('EffectiveToDate')+' '+'(M/D/YYYY)',
                            name: "Effectiveto",
                            value: new Date('12/31/2099').toLocaleDateString(),
                            placeholder: "",
                            config: {
                                format: "MM/DD/YYYY",
                                minDate: new Date(),
                                onChange: this.setTimerDate,
                                maxDate: false
                            },
                            validationRules: { "required": true },
                        }, {
                            astype: "RadioField",
                            label: this.$t('IsRuleApllicableToAll'),
                            name: "allutilities",
                            value: "0",
                            config: {
                                options: [{ value: "1", name: "Yes" }, { value: "0", name: "No" }],
                                onChange: this.onChangeApplicable
                            },
                            validationRules: { "required": false, max: 100 },
                        },
                        {
                            astype: "SearchableSelectField",
                            label: this.$t('ClientId'),
                            name: "ContractName",
                            value: "",
                            placeholder: "Select",
                            visibility: true,
                            isSearch: false,
                            config: {
                                options: [],
                                actionButtons: {
                                    selectAll: true,
                                    active: true,
                                    inactive: true,
                                    clear: true
                                },
                                isMultiple: false,
                                groupFields: ['groupText'],
                                minSearchLength: 0,
                                statusFieldConfig: {
                                    fieldName: 'status',
                                    activeValues: ['Active', 'active'],
                                    inactiveValues: ['Inactive', 'inactive'],
                                    activeColor: '#28a745',
                                    inactiveColor: '#dc3545'
                                },
                                onChange: this.onSelectionChange
                            },
                            validationRules: {
                                "required": true
                            },
                        },
                        {
                            astype: "SearchableSelectField",
                            label: this.$t('UtilityName'),
                            name: "UtilityName",
                            value: "",
                            placeholder: "Select Utility Name",
                            visibility: true,
                            isSearch: false,
                            config: {
                                options: [],
                                actionButtons: {
                                selectAll: true,
                                active: true,
                                inactive: true,
                                clear: true},
                                groupFields: [],
                                isMultiple: true,
                                minSearchLength: 0,
                                statusFieldConfig: {
                                    fieldName: 'status',
                                    activeValues: ['Active', 'active'],
                                    inactiveValues: ['Inactive', 'inactive'],
                                    activeColor: '#28a745',
                                    inactiveColor: '#dc3545'
                                },
                            },
                            validationRules: {
                                "required": true
                            },
                        },

                    ],

                }
            ],
            buttons: [
                {
                    type: "submit",
                    class: "btn btn-success",
                    text: "<i class='fa fa-save pr-2'></i>" + this.$t('Save'),
                    onClick: this.CreateClone
                },
                {
                    type: "button",
                    class: "btn btn-danger",
                    text: "<i class='fa fa-close pr-2'></i>" + this.$t('Cancel'),
                    onClick: this.CloseCloneModel,
                },
            ],
            leftSearchFields: Schema.leftsearchSchema,
            searchByName: '',
            searchByClientName: '',
            utilities: '',
            searchByState: [],
            SortBy: '',
            SortExp: '',
            noRecords: '',
            PageSize: "10",
            PageNumber: "1",
            TotalRecords: 0,
            CurrentPage: 1,
            TotalPages: 0,
            searchCondition: '',
            ListingData: [],
            servicePlanId: '',
            isBillingHistoryPopup:false,
            isBillingType:false,
            setupId:32
        }
    },
    created: async function () {
        var vm = this;
        this.isBillingType = localStorage.getItem('billingType') === 'USIC' ? true : false; 
        await vm.ManageLeftSearchFields();
        // await vm.CheckFeaturesForCompany('USICBILLING');
        await vm.FetchData();
        await vm.GetCompanylist();
        await vm.GetGroupList();
        
        await Schema.bindleftCommonSearchdropdown(vm,"STATE");
        await Schema.bindleftCommonSearchdropdown(vm,"UTILITIES");
    },
    methods: {
        ManageLeftSearchFields: async function(){
            const removeFields = (fields) => {
                this.leftSearchFields = this.leftSearchFields.filter(
                    ele => !fields.includes(ele.fieldName)
                );
            };
            if (this.isBillingType) {
                 removeFields(['ServiceName']);
            } else {
                removeFields(['CONTRACTNAME', 'UtilityName', 'STATE']);
            }
        },
        // CheckFeaturesForCompany: async function (type) {
        //     var vm = this;
        //     var appendingUrl = `featureCode=${type}`;
        //     await DataService.CheckExtraFeatures(appendingUrl).then(function (response) {
        //         if(type == 'USICBILLING'){
        //             if (response.data == true) {
        //                  vm.isBillingType = true;
        //             } 
        //         }
        //     });
        // },
        OpenRuleDetail: function (data) {
            var vm = this;
            if(this.isBillingType){
                vm.$router.push({ name: 'ManageConfiguration', params: { id: data.CONFIGURATION_ID,serviceId:data.SERVICE_ID,mode :'View' } });
            }
            else{
                vm.$router.push({ name: 'ManageConfiguration', params: { id: data.CONFIGURATION_ID,serviceId:data.BILLING_SERVICE_ID,mode :'View' } });
            }
          
            // if(this.isBillingType){
            //     vm.getNodeConfiguration(data.CONFIGURATION_ID,data.SERVICE_ID,'Edit')
            // }
            // else{
            //     vm.$router.push({ name: 'ManageConfiguration', params: { id: data.CONFIGURATION_ID,serviceId : data.BILLING_SERVICE_ID,mode :'Edit' } });
            // }
        },
        getNodeConfiguration: function (configId,serviceId,mode) {
            let ths = this;
            var prms = `configId=${configId}&serviceId=${serviceId}&isIncludeGlobalService=true&isView=${mode}`;
            DataService.GetNodeConfiguration(prms).then(function (res) {
                if (res?.data?.length > 0 && res.data[0]?.CONFIG_ID != null && res.data[0]?.SERVICE_ID != null) {
                    configId = res.data[0].CONFIG_ID;
                    serviceId = res.data[0].SERVICE_ID;
                    ths.$router.push({ name: 'ManageConfiguration', params: { id: configId, serviceId : serviceId,mode :'Edit' } });
                }
            });
        },
        FetchData: async function () {
            var vm = this;
            const url = `searchByName=${vm.searchByName}&searchByClientName=${vm.searchByClientName}&utilities=${vm.utilities}&searchByState=${vm.searchByState}&sortBy=${vm.SortBy}&sortExp=${vm.SortExp}&pageSize=${vm.PageSize}&pageNumber=${vm.PageNumber}&Plan_service_id=${vm.servicePlanId}`
            try {

                const response = await DataService.GetBillingRuleList(url);
                if (response.data && response.data.length > 0) {
                    vm.Headers.forEach((column) => {
                        column.settings = null;

                        if (["EFFICATIVE_DATE_FROM", "EFFICATIVE_DATE_TO", "STATUS_ID","RULE_NAME","CREATED_AT","MODIFIED_AT","MODIFIED_BY_NAME"].includes(column.COLUMN_NAME)) {
                            column.settings = { isInSlot: true };
                        }
                        if(this.isBillingType == true){
                            if (["CATEGORY_NAME","CLIENT_NAME","UTILITYNAME","STATENAME"].includes(column.COLUMN_NAME)) {
                                column.settings = { isInSlot: true };
                            }
                            if(column.COLUMN_NAME == "CATEGORY_NAME" || column.COLUMN_NAME == "CLIENT_NAME" || column.COLUMN_NAME == "UTILITYNAME" || column.COLUMN_NAME == "STATENAME"){
                                column.VISIBLE=true
                            }
                        }
                        else{
                            if(column.COLUMN_NAME == "SERVICE_NAME" || column.COLUMN_NAME == "CREATED_AT" || column.COLUMN_NAME == "MODIFIED_BY_NAME" || column.COLUMN_NAME == "MODIFIED_AT"){
                                column.VISIBLE=true;
                            }
                            
                        }
                    });
                    vm.BillingRuleData = response.data;
                    vm.BillingRuleData.forEach((element) => {
                        ['EFFICATIVE_DATE_FROM', 'EFFICATIVE_DATE_TO','CREATED_AT','MODIFIED_AT'].forEach((key) => {
                            if (element[key]) {
                                element[key] = new Date(element[key]);
                            }
                        });
                    });
                    vm.listheaderbuttons[2].isdisabled = true;
                    vm.TotalRecords = response.data[0].TOTAL_RECORDS;
                    vm.TotalPages = Math.ceil(vm.TotalRecords / vm.PageSize);
                    vm.CurrentPage = vm.PageNumber;
                    vm.noRecords = false;

                } else {
                    vm.BillingRuleData = [];
                    vm.TotalRecords = 0;
                    vm.noRecords = true;
                }

            } catch (error) {
                console.error("Error fetching data:", error);
            }
        },
        CreateClone: async function () {
            debugger;
            var vm = this;
            const isValid = await vm.$refs.validatePlan.validateForm.validate();
            if (!isValid) {
                this.isLoading = false;
                return;
            }
            var id = vm.cloneItem.CONFIGURATION_ID;
            var BILLING_SERVICE_ID = vm.cloneItem.BILLING_SERVICE_ID;
            var rulename = vm.$refs.validatePlan.getPropertyValue("RuleName", "value");
            var companyname = vm.$refs.validatePlan.getPropertyValue("CompanyName", "value");
            var effectivefrom = vm.$refs.validatePlan.getPropertyValue("Effectivefrom", "value");
            var effectiveto = vm.$refs.validatePlan.getPropertyValue("Effectiveto", "value");
            var contractname = vm.$refs.validatePlan.getPropertyValue("ContractName", "value");
            var isruleapplication = vm.$refs.validatePlan.getPropertyValue("allutilities", "value");
            var selectUtility = vm.$refs.validatePlan.getPropertyValue("UtilityName", "value");
            const obj = {
                Id: id,
                BILLING_SERVICE_ID: BILLING_SERVICE_ID,
                Client_Id: contractname,
                RuleName: rulename,
                CompanyName: companyname,
                EffectiveFrom: effectivefrom,
                EffectiveTo: effectiveto,
                ContractName: contractname,
                isRuleApplication: isruleapplication,
                SelectedUtility: selectUtility,
            }
            var jsonData = JSON.stringify(obj);
            await DataService.CreateRuleClone(jsonData).then((response) => {
                if (response.data != '') {
                    if (response.data == 0) {
                        this.ShowAlert(this.$t('AddedSuccess', [this.$t('Clone')]), "Success", true, this.$t('Alert'));
                        vm.FetchData();
                        vm.cloneItem = [];
                        vm.CloseCloneModel();
                    }
                    else {
                        this.ShowAlert(this.$t('ErrorWhileSaving', [this.$t('Clone')]), "danger", true, this.$t('Alert'));
                    }
                }
            })

        },
        onChangeApplicable() {
            var utilityselectval = this.$refs.validatePlan.getPropertyValue("allutilities", "value");
            switch (utilityselectval) {
                case "1":
                    this.FormSchema[0].Data[6].visibility = false;
                    break;
                default:
                    this.FormSchema[0].Data[6].visibility = true;
            }
        },
        setTimerDate: function (x, y, z) {
            var vm = this;
            if (y.name == "Effectivefrom") {
                vm.$refs.validatePlan.updateProperty("Effectivefrom", "config.minDate", x);
                vm.$refs.validatePlan.UpdateKeyValue();
            }
        },
        GetCompanylist: async function() {
            var vm = this;

            await DataService.GetDdlCompanyList().then((response) => {
                if (response.data != '') {
                    if (response.data.length) {

                        response.data.forEach(element => {
                            var obj = {
                                name: element.Company_Name,
                                value: element.company_id
                            }
                            vm.FormSchema[0].Data[1].config.options.push(obj);
                        })
                    }
                }
            })
        },
        GetGroupList: async function() {
            var vm = this;
            await DataService.GetDdlGroupList().then((response) => {
                if (response.data) {
                    if (response.data.length) {
                        response.data.forEach(element => {
                            var obj = {
                                name: element.CHILD_NAME,
                                value: element.CHILD_USER_ID
                            }
                            vm.FormSchema[0].Data[5].config.options.push(obj);
                        });
                    }
                }
            })
        },

        DeleteData: function () {
            var vm = this;
            var val = "";
            $('.chkItems:checkbox:checked').not("[id^='chkAll']").each(function () {
                if (val.length > 0)
                    val += ',';
                val += $(this).val();
            });
            if (val.length > 0) {
                vm.confirmR(vm.$t("ConfirmDelete"), true, (vm.$t("Delete") + "  " + vm.$t("SERVICE")), function () {
                    let url = `ids=${val}&tableName=TALYGEN_BE_CLIENT_CONFIGURATION&primaryKey=CONFIGURATION_ID`;
                    DataService.Delete(url).then(response => {
                        if (response.data == "DeletedSuccess") {
                            vm.ShowAlert(vm.$t('DeletedSuccessfully'), "Success", true, vm.$t('Alert'));
                        } else {
                            vm.ShowAlert(vm.$t('DeletedError', [vm.$t('val')]), "failure", true, vm.$t('Alert'));
                        }
                        vm.FetchData();
                    });
                });
            }
            else {
                vm.ShowAlert(vm.$t("Selectanyrecordtodelete"), "failure", true, vm.$t("Alert"));
            }
        },
        renderActions(row) {
            let rtnActionArray = [];
            this.listActions.forEach(actionItem => {
                let action = { ...actionItem };
                action.isVisible = true;
                rtnActionArray.push(action);
            });
            return rtnActionArray;
        },
        leftCommonSearch: function (value) {
            this.PageNumber = value.PageNumber;
            this.isPaged = 1;
            if (value.searchCondition) {
                let str = value.searchConditionJson;
                const regex = /(RULE_NAME|CLIENT_NAME|UTILITYNAME|STATENAME)\s*(?:LIKE\s*|='?)\s*['"]?%?([^'"]+)['"]?%?/i;
                const m = str.match(regex);
                const column = m[1];
                const values = m[2];
                switch (column) {
                    case "RULE_NAME":
                        this.searchByName = values;
                        break;
                    case "CLIENT_NAME":
                        this.searchByClientName = values;
                        break;
                    case "UTILITYNAME":
                        this.utilities = values
                        break;
                    case "STATENAME":
                        this.searchByState = values;
                        break;
                }
            } else {
                this.searchByState = [];
                this.utilities = "";
                this.searchByClientName = "";
                this.searchCondition = "";
                this.searchByName="";
            }
            this.FetchData();
        },
        actionButtonClick: function (callbackfunction, item, index, event) {
            switch (callbackfunction) {
                case "ViewHistory":
                    this.OpenHistoryModal(item);
                    break;
                case "ResourceImpact":
                    this.ResourceImpact(item);
                    break;
                case "CloneRule":
                    this.cloneItem = item,
                        this.CloneRule(item);
                    break;
                case "ViewBillingRule":
                        this.ViewBillingRule(item);
                    break;
                case "EditRuleService":
                    this.EditRuleService(item);
                    break;
                    case "BillingViewHistory":
                    this.BillingViewHistory(item);
                    break;
            }
        },
        ViewBillingRule(data){
            var vm = this;
            if(this.isBillingType){
                vm.$router.push({ name: 'ManageConfiguration', params: { id: data.CONFIGURATION_ID,serviceId:data.SERVICE_ID,mode :'View' } });
            }
            else{
                vm.$router.push({ name: 'ManageConfiguration', params: { id: data.CONFIGURATION_ID,serviceId:data.BILLING_SERVICE_ID,mode :'View' } });
            }
            // vm.$router.push({ name: 'ManageConfiguration', params: { id: item.CONFIGURATION_ID,serviceId:item.BILLING_SERVICE_ID,mode :'View' } });
        },
        BillingViewHistory(data) {
            debugger;
            var vm = this;
            vm.CONFIGURATION_ID = data.CONFIGURATION_ID;
            vm.BILLING_SERVICE_ID= this.isBillingType == true ? data.SERVICE_ID: data.BILLING_SERVICE_ID;
            vm.setupId = data.SETUP_ID;
            vm.isBillingHistoryPopup = true;
        },
        EditRuleService: async function (item) {
            var vm = this;
            if(this.isBillingType){
                vm.getNodeConfiguration(item.CONFIGURATION_ID,item.SERVICE_ID,'Edit')
            }
            else{
                vm.$router.push({ name: 'ManageConfiguration', params: { id: item.CONFIGURATION_ID,serviceId:item.BILLING_SERVICE_ID,mode :'Edit' } });
            }
        },
        CloneRule(item) {
            var vm = this;
            vm.isCloneModel = true;
            vm.GetDDLCompanyContractClients();
            vm.FormSchema[0].Data[1].value =item.COMPANY_ID;
            // vm.$refs.validatePlan.updateProperty("CompanyName", "value", item.COMPANY_ID);
            // vm.$refs.validatePlan.UpdateKeyValue();
        },
        GetDDLCompanyContractClients: async function () {
            var vm = this;
            vm.isLoading = true;
            var url = `reqFrom=CUSTOM`;
            await locateBillingService.getClientList(url).then(response => {
                vm.isLoading = false;
                vm.clientList = response.data.items;
                vm.$refs.validatePlan.updateProperty("ContractName", "config.options", vm.clientList);
                vm.$refs.validatePlan.UpdateKeyValue();
            }).catch(error => {
                vm.isLoading = false;
                vm.clientList = []; 
                vm.$refs.validatePlan.updateProperty("ContractName", "config.options", vm.clientList);
                vm.$refs.validatePlan.UpdateKeyValue();
                console.error('Error fetching client list:', error);
            }).finally(() => {
                vm.isLoading = false;
            });
        },
        onSelectionChange: async function(value, x) {
            var vm = this;
            vm.isLoading = true;
            vm.selectedClientId = x;
            var url = `clientId=${x}&configId=&reqFrom=&clientIds=`;
            await locateBillingService.getUtilityList(url).then(response => {
                vm.isLoading = false;
                let SelectedUtilityList = [];
                debugger;
                var UtilityList = response.data;
                if (UtilityList != null) {
                    UtilityList.forEach(item => {
                        let obj = {
                            description: null,
                            displayValue: item.UTILITY_NAME,
                            groupText: null,
                            groupValue: null,
                            metaData: null,
                            text: item.UTILITY_NAME,
                            value: item.UTILITY_ID
                        };
                        SelectedUtilityList.push(obj);
                    });
                     vm.$refs.validatePlan.updateProperty("UtilityName", "config.options", SelectedUtilityList);
                     vm.$refs.validatePlan.UpdateKeyValue();
                }
            }).catch(error => {
                vm.isLoading = false;
            }).finally(() => {
                vm.isLoading = false;
            });
        },
        CloseCloneModel() {
            var vm = this;
            vm.$refs.validatePlan.updateProperty("RuleName", "value", "");
            vm.$refs.validatePlan.updateProperty("CompanyName", "value", "");
            vm.$refs.validatePlan.updateProperty("ContractName", "value", "");
            this.isCloneModel = false;
            this.cloneItem = [];
            this.FetchData();
        },

        commonHeaderButtonClick: function (event) {
            switch (event.callbackfunction) {
                case "AddBillingRule":
                    this.AddBillingRule();
                    break;
                case "ExportToExcel":
                    this.DownloadExcelData();
                    break;
                case "DeleteRecord":
                    this.DeleteData();
                    break;
            }
        },
        DownloadExcelData: async function () {
            var vm = this;
            if(this.isBillingType == true){
                await DataService.RuleExportToExcel().then(function (response) {
                    if (response.data != "" && response.data != null) {
                        if (response.data.length > 0) {
                            vm.ConvertJSONToCSV(response.data, "BillingRuleExport", true);
                        }
                    }
                })
            }
            else{
                const url = `searchByName=${vm.searchByName}&searchByClientName=${vm.searchByClientName}&utilities=${vm.utilities}&searchByState=${vm.searchByState}&sortBy=${vm.SortBy}&sortExp=${vm.SortExp}&pageSize=${vm.TotalRecords}&pageNumber=${vm.PageNumber}&Plan_service_id=${vm.servicePlanId}`
                await DataService.GetBillingRuleList(url).then(function (response) {
                    debugger;
                    if (response.data != "" && response.data != null) {
                        if (response.data.length > 0) {
                            vm.ConvertJSONToCSV(response.data, "BillingRuleExport", true);
                        }
                    }
                })
            }
        },
        ConvertJSONToCSV: function (jsonData, filename, showHeader) {
            const jsonString = JSON.stringify(jsonData);
            const data = JSON.parse(jsonString);
            var excludeColumns=[];
            var headerMap ={};
            if(this.isBillingType == true){
                excludeColumns = ['CONFIGURATION_ID','SERVICE_ID','CONDITION', 'INVOICE_TEMPLATE', 'DURATION', 'AUTO_INVOICE', 'BILLING_SERVICE_ID','MODIFIED_BY_NAME','CREATED_AT',
                'INVOICE_TEMPLATE_NAME','MODIFIED_AT','Utility Name','SERVICE_NAME','STATUS_ID','TEMPORARY_CLONED_FROM','COMPANY_ID','SETUP_ID','ROWNUMBERS','TOTAL_RECORDS','ROWNUMBER'];
           
                headerMap = {
                    'RULE NAME': 'Rule Name', 'CLIENT NAME': 'Client Name', 'UTILITY NAME': 'Utility Name','COMPANYNAME':'Company Name', 'CATEGORY_NAME': 'Category Name', 'STATE':'State Name','CHARGE_TYPE':'Charge Type','STATUS':'Status',
                    'EFFECTIVE_DATE_FROM': 'Effective Date From','EFFECTIVE_DATE_TO':'Effective Date To','CREATED_BY_NAME' :'Created By Name'
                   
                };
            }
            else
            {
                excludeColumns = ['CONFIGURATION_ID', 'INVOICE_TEMPLATE','CONDITION', 'DURATION', 'AUTO_INVOICE', 'BILLING_SERVICE_ID', 'CLIENT_NAME','CHARGE_TYPE',
                'INVOICE_TEMPLATE_NAME','Utility Name','COMPANYNAME','STATUS_ID','STATENAME','TEMPORARY_CLONED_FROM','SETUP_ID','CATEGORY_NAME','ROWNUMBERS','TOTAL_RECORDS','UTILITYNAME'];
           
                headerMap = {
                    'ROWNUMBER': 'Sr No',
                    'RULE_NAME': 'Rule Name', 'SERVICE_NAME': 'Service Name', 'CLIENT_NAME': 'Client Name', 'UTILITYNAME': 'Utility Name', 'CATEGORY_NAME': 'Category Name', 'STATENAME':'State Name','STATUS_NAME':'Status Name',
                    'EFFICATIVE_DATE_FROM': 'Effective From','EFFICATIVE_DATE_TO':'Effective To','CREATED_BY_NAME' :'Created By','CREATED_AT':'Created At','MODIFIED_BY_NAME':'Modified By',
                    'MODIFIED_AT':'Modified At'
                };
            }
            
            if (!Array.isArray(data) || data.length === 0) {
                console.warn("No valid data to convert.");
                return;
            }
            if (data.length > 0) {
                const headers = Object.keys(data[0]);
                const filteredHeaders = headers.filter(header => !excludeColumns.includes(header));
                const mappedHeaders = filteredHeaders.map(header => headerMap[header] || header);
                const rows = data.map(row => {
                    return mappedHeaders.map(mappedHeader => {
                        const originalHeader = filteredHeaders[mappedHeaders.indexOf(mappedHeader)];
                        let cellValue = row[originalHeader] !== undefined && row[originalHeader] !== null ? String(row[originalHeader]) : '';
                        if (cellValue.includes(',') || cellValue.includes('\n') || cellValue.includes('"')) {
                            cellValue = `"${cellValue.replace(/"/g, '""')}"`;
                        }

                        return cellValue;
                    }).join(',');
                });
                const csvContent = (showHeader ? [mappedHeaders.join(',')] : []).concat(rows).join('\n');
                const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });
                const link = document.createElement('a');
                link.setAttribute('href', URL.createObjectURL(blob));
                link.setAttribute('download', `${filename}.csv`);
                link.click();
            } else {
                console.log("No valid data to convert.");
            }
        },
        sortdata: function (sortBy) {

            this.SortBy = sortBy;
            var sortExp = 'ASC';
            if (this.SortExp == 'ASC') {
                sortExp = 'DESC';
            }
            this.SortExp = sortExp;
            this.SortBy = sortBy;
            this.SortExp = sortExp;
            this.PageNumber = 1;
            this.FetchData();
        },
        pagerMethod: function (value) {
            this.PageSize = value.PageSize;
            this.PageNumber = value.PageNumber;
            this.FetchData();
        },
        getStatusClassList: function (status) {

            var returnClass = '';
            switch (status) {
                case 'Active':
                    returnClass = 'px-2 text-center text-white d-block bg-success';
                    break;
                case 'Inactive':
                    returnClass = 'px-2 text-center text-white d-block bg-danger';
                    break;
                default:
                    returnClass = '';
            }
            return returnClass;
        },
        AddBillingRule: function () {
            var vm = this;
            debugger;
            vm.$router.push({ name: 'ManageConfiguration', params: { id: 0,serviceId:0,mode :'Add' } });
        }

    }
}
</script>

